  ('prd-fathering-excellence', 'components', 8, '{"name":"Knowledge Agent","owner":"Erik Companhone","status":"Planned","desc":"Retrieval over the vetted corpus; cited generation; no unvetted claims."}'::jsonb, 8, 'Seed', now()),
  ('prd-fathering-excellence', 'metrics', 1, '{"metric":"Answer-save latency","target":"p95 under 300 ms","method":"Server-acknowledged timing on the responses write path."}'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'metrics', 2, '{"metric":"Assessment completion (starters)","target":"at or above 75%","method":"Completions divided by starts, per launch cohort."}'::jsonb, 2, 'Seed', now()),
  ('prd-fathering-excellence', 'metrics', 3, '{"metric":"Crew join rate (new completers)","target":"at or above 40%","method":"Crew joins within 7 days of results."}'::jsonb, 3, 'Seed', now()),
  ('prd-fathering-excellence', 'metrics', 4, '{"metric":"Week-4 Rhythm rate","target":"at or above 45%","method":"Members logging in week 4 of membership."}'::jsonb, 4, 'Seed', now()),
  ('prd-fathering-excellence', 'metrics', 5, '{"metric":"Expedition cohort completion","target":"at or above 55%","method":"Completions per enrolled cohort."}'::jsonb, 5, 'Seed', now()),
  ('prd-fathering-excellence', 'metrics', 6, '{"metric":"Voice semantic mapping accuracy","target":"at or above 95%","method":"Against a human-labeled set; below 92% blocks a dialect cohort."}'::jsonb, 6, 'Seed', now()),
  ('prd-fathering-excellence', 'metrics', 7, '{"metric":"WAFA (North Star)","target":"up and to the right, weekly","method":"Distinct fathers logging one intentional action per week."}'::jsonb, 7, 'Seed', now()),
  ('prd-fathering-excellence', 'metrics', 8, '{"metric":"Verified Completions (Business North Star)","target":"weekly by channel","method":"ProofRail-signed records issued."}'::jsonb, 8, 'Seed', now()),
  ('prd-fathering-excellence', 'fr', 1, '{"stmt":"The platform delivers the Keystone Father Profile as one item per screen on a uniform 1-to-5 scale, autosaving every answer and resuming on any device.","fit":"A member completes the instrument across multiple sessions and devices with no lost answers; save p95 under 300 ms. Test and Demonstration.","pri":"Must","comp":"Assessment Engine"}'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'fr', 2, '{"stmt":"The engine loads an instrument as data (items, sections, dimensions, factors, scale anchors, scoring weights, norm tables, clarifications, observer variant) with no code change per instrument.","fit":"A 100-item and a 138-item instrument both run from configuration. Inspection and Test.","pri":"Must","comp":"Assessment Engine"}'::jsonb, 2, 'Seed', now()),
  ('prd-fathering-excellence', 'fr', 3, '{"stmt":"On completion the platform scores against the licensed rubric and renders results strengths-first, growth-areas-second, norm-referenced in plain words, never a grade, always ending in the member’s first three actions.","fit":"Results match the licensed scoring exactly and always present a trail. Inspection and Test.","pri":"Must","comp":"Plan Engine"}'::jsonb, 3, 'Seed', now()),
  ('prd-fathering-excellence', 'fr', 4, '{"stmt":"The plan engine maps the member’s lowest factors and children’s life-stages to an ordered plan of at most three active items (one module, one field action, one Crew or Expedition step).","fit":"Every member sees exactly three active items derived from mapping tables; recommendation tap-through is measured. Test.","pri":"Must","comp":"Plan Engine"}'::jsonb, 4, 'Seed', now()),
  ('prd-fathering-excellence', 'fr', 5, '{"stmt":"The platform forms Crews of 5 to 8 men matched on child life-stage, region, and situation tags, with an Anchor pairing and a merge offer when a Crew falls below four active men after six weeks.","fit":"New completers are offered a matched Crew; small Crews trigger a merge. Test and Demonstration.","pri":"Must","comp":"Community"}'::jsonb, 5, 'Seed', now()),
  ('prd-fathering-excellence', 'fr', 6, '{"stmt":"Messaging is Crew-scoped and Anchor-scoped only; leaders broadcast and hold public sessions but cannot direct-message members.","fit":"No path exists for a leader-to-member DM or a stranger DM. Inspection and Test.","pri":"Must","comp":"Community"}'::jsonb, 6, 'Seed', now()),
  ('prd-fathering-excellence', 'fr', 7, '{"stmt":"The Rhythm records one intentional fathering action per week with optional note, with milestone celebrations at 4, 12, 26, and 52 weeks and a protection pass earned per completed Expedition.","fit":"One log per week counts; no daily platform streak exists; milestones fire only at the four marks. Test.","pri":"Must","comp":"Engagement"}'::jsonb, 7, 'Seed', now()),
  ('prd-fathering-excellence', 'fr', 8, '{"stmt":"Expeditions run fixed-length cohorts with daily check-ins and Crew visibility, and issue a ProofRail-signed completion record on finish.","fit":"A completed Expedition produces a verifiable record. Test and Demonstration.","pri":"Must","comp":"Engagement"}'::jsonb, 8, 'Seed', now()),
  ('prd-fathering-excellence', 'fr', 9, '{"stmt":"Waypoints advance rank on verified behavior only (profile complete, first Expedition, sustained Rhythm plus Crew service, capstone), never on purchases.","fit":"No purchase advances rank; every rank maps to verifiable behaviors. Inspection.","pri":"Must","comp":"Engagement"}'::jsonb, 9, 'Seed', now()),
  ('prd-fathering-excellence', 'fr', 10, '{"stmt":"ProofRail signs each completion record with a hash, RFC 3161 timestamp, course and version, and requirement attestations, appends it to a transparency log, and verifies publicly without a Fathers.com account.","fit":"A third party verifies a certificate while the platform is offline; revocation is checked on every verify; zero false-valids. Test.","pri":"Must","comp":"ProofRail"}'::jsonb, 10, 'Seed', now()),
  ('prd-fathering-excellence', 'fr', 11, '{"stmt":"Institutional reporting exposes completion, attendance, and certificate validity only, always aggregated with a minimum cohort size of ten; assessment scores are never visible to any institution.","fit":"No employer, court, corrections, or military view returns an individual score or a sub-ten cohort. Inspection and Test.","pri":"Must","comp":"Institutional Modes"}'::jsonb, 11, 'Seed', now()),
  ('prd-fathering-excellence', 'fr', 12, '{"stmt":"Corrections mode runs a full class session offline, captures attendance and module completion, and syncs verified completions when connectivity returns.","fit":"A facilitator runs a session with no connectivity and syncs later with no data loss. Demonstration and Test.","pri":"Must","comp":"Institutional Modes"}'::jsonb, 12, 'Seed', now()),
  ('prd-fathering-excellence', 'fr', 13, '{"stmt":"A crisis disclosure in free text routes to a trained human within one hour, pauses all gamification and nudges for that member, and surfaces professional resources, never punitively and never as automated therapy.","fit":"A seeded disclosure triggers routing within one hour and a gamification pause. Test and Drill.","pri":"Must","comp":"Community"}'::jsonb, 13, 'Seed', now()),
  ('prd-fathering-excellence', 'fr', 14, '{"stmt":"Voice mode delivers the assessment eyes-free with streaming speech, grounded clarification from the curated corpus only, and full tap parity with mid-item switching.","fit":"End-of-speech to first audio under 1.5 s p90; semantic mapping at or above 95 percent; any member can switch to tap without loss. Test.","pri":"Should","comp":"Voice Mode"}'::jsonb, 14, 'Seed', now()),
  ('prd-fathering-excellence', 'fr', 15, '{"stmt":"The knowledge agent answers only from the vetted corpus with mandatory citations, files a content-gap ticket when coverage is missing, and lives behind the plan rather than as a front-door chatbot.","fit":"Zero uncited generative claims in the audit sample; out-of-corpus probes defer honestly. Test.","pri":"Should","comp":"Knowledge Agent"}'::jsonb, 15, 'Seed', now()),
  ('prd-fathering-excellence', 'nfr', 1, '{"stmt":"The assessment write path sustains modeled launch peak (about 420 writes per second) without blocking the UI.","fit":"A synthetic run at twice modeled peak (10,000 concurrent sessions) holds the save budget. Load test.","pri":"Must","comp":"Assessment Engine"}'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'nfr', 2, '{"stmt":"The platform meets WCAG 2.1 AA and Section 508 globally, including keyboard paths, screen-reader labels on the 1-to-5 control, captions, and transcripts.","fit":"An accessibility audit passes AA on every launch surface. Inspection and Test.","pri":"Must","comp":"Assessment Engine"}'::jsonb, 2, 'Seed', now()),
  ('prd-fathering-excellence', 'nfr', 3, '{"stmt":"Console roles require MFA; staff access is least-privilege with break-glass audit; secrets live in a managed vault.","fit":"No console login without MFA; break-glass reads land in the audit log. Inspection and Test.","pri":"Must","comp":"Institutional Modes"}'::jsonb, 3, 'Seed', now()),
  ('prd-fathering-excellence', 'nfr', 4, '{"stmt":"Backup and disaster recovery meet RPO 1 hour and RTO 4 hours with a quarterly restore drill.","fit":"A restore drill meets the objectives. Test.","pri":"Must","comp":"ProofRail"}'::jsonb, 4, 'Seed', now()),
  ('prd-fathering-excellence', 'nfr', 5, '{"stmt":"The assessment path holds 99.9 percent availability during the launch wave.","fit":"Measured uptime on the assessment path meets the target. Test.","pri":"Should","comp":"Assessment Engine"}'::jsonb, 5, 'Seed', now()),
  ('prd-fathering-excellence', 'eval', 1, '{"dim":"Voice semantic mapping","metric":"Colloquial answer to 1-to-5 mapping accuracy against a human-labeled set, stratified by dialect","thresh":"at or above 95%; below 92% blocks that cohort","comp":"Voice Mode"}'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'eval', 2, '{"dim":"Voice grounding guardrail","metric":"Share of clarification answers drawn only from the curated corpus; out-of-corpus deferral rate","thresh":"100% grounded; improvised interpretation is a hard fail","comp":"Voice Mode"}'::jsonb, 2, 'Seed', now()),
  ('prd-fathering-excellence', 'eval', 3, '{"dim":"Knowledge agent hallucination guardrail","metric":"Uncited generative claims in the audit sample","thresh":"zero uncited claims","comp":"Knowledge Agent"}'::jsonb, 3, 'Seed', now()),
  ('prd-fathering-excellence', 'eval', 4, '{"dim":"Knowledge agent gap handling","metric":"Out-of-corpus probes that defer honestly and file a gap ticket","thresh":"at or above 99%","comp":"Knowledge Agent"}'::jsonb, 4, 'Seed', now()),
